        const limit = tight ? (n >> (pos - 1)) & 1 : 1;
        let res = 0;

        for (let d = 0; d <= limit; d++) {
            const newTight = tight && (d === limit);
            const newCount = count - d;
            const newBits = bits + d;
            if (newCount >= 0) {
                res += dp(pos - 1, newCount, newTight, newBits);
            }
        }

        memo.set(key, res);
        return res;
    }

    const totalBits = n.toString(2).length;
    let result = 0;

    // We need to find numbers x in [1, n] where depth[x] = k
    // So we iterate over possible bit counts and check their depth
    for (let targetBits = 1; targetBits <= maxBits; targetBits++) {
        if (depth[targetBits] === k - 1) {
            result += dp(totalBits, targetBits, true, 0);
        }
    }

    return result;
}
