    // Precompute the popcount-depth for numbers up to a certain limit (like 60 bits)
    const maxBits = 60;
    const depth: number[] = new Array(maxBits + 1).fill(0);
    depth[1] = 0;
    for (let i = 2; i <= maxBits; i++) {
        const pop = i.toString(2).split('1').length - 1;
        depth[i] = depth[pop] + 1;
    }

    // Memoization for the DP function
    const memo: Map<string, number> = new Map();

    function dp(pos: number, count: number, tight: boolean, numBits: number): number {
        if (pos === 0) {
            return (count === numBits) && (depth[count] === k - 1) ? 1 : 0;
        }
        const key = `${pos},${count},${tight},${numBits}`;
        if (memo.has(key)) {
            return memo.get(key)!;
        }

        const maxDigit = tight ? (n >> (pos - 1)) & 1 : 1;
        let res = 0;

        for (let d = 0; d <= maxDigit; d++) {
            const newTight = tight && (d === maxDigit);
            const newCount = count + d;
            const newNumBits = numBits + (d === 1 ? 1 : 0);
            res += dp(pos - 1, newCount, newTight, newNumBits);
        }

        memo.set(key, res);
        return res;
    }

    const bits = n.toString(2).length;
    return dp(bits, 0, true, 0);
